 2→
 3→.grid {
 4→  display: grid;
 5→  grid-template-columns: repeat(var(--grid-columns, 4), 1fr);
 6→  gap: $space-2;
 7→  flex: 1;
 8→  overflow-y: auto;
 9→  padding: $space-2;
