  1→@use '../../styles/tokens' as *;
  2→
  3→.search-dropdown {
  4→  position: relative;
  5→  flex-shrink: 0;
  6→}
  7→
  8→.search-dropdown__trigger {
  9→  display: flex;
 10→  align-items: center;
 11→  gap: $space-1;
 12→  padding: $space-1 $space-2;
 13→  border: none;
 14→  border-radius: $radius-kbd;
 15→  background: $text-100;
 16→  font-family: $font-family;
 17→  font-size: $font-sm;
 18→  color: $text-600;
 19→  cursor: pointer;
 20→  white-space: nowrap;
 21→  transition: background-color $transition-fast ease;
 22→  line-height: 1;
 23→  height: $search-dropdown-trigger-height;
 24→
 25→  &:hover {
 26→    background: $border-200;
 27→  }
 28→
 29→  &:focus-visible {
 30→    outline: 2px solid $color-accent;
 31→    outline-offset: -1px;
 32→  }
 33→}
 34→
 35→.search-dropdown__trigger-label {
 36→  max-width: 120px;
 37→  overflow: hidden;
 38→  text-overflow: ellipsis;
 39→}
 40→
 41→.search-dropdown__trigger-chevron {
 42→  flex-shrink: 0;
 43→  transition: transform $transition-fast ease;
 44→
 45→  &--open {
 46→    transform: rotate(180deg);
 47→  }
 48→}
 49→
 50→.search-dropdown__menu {
 51→  position: absolute;
 52→  top: calc(100% + $space-2);
 53→  right: 0;
 54→  min-width: $search-dropdown-menu-min-width;
 55→  max-height: $search-dropdown-menu-max-height;
 56→  overflow: hidden;
 57→  background-color: $color-surface;
 58→  border: 1px solid $border-100;
 59→  border-radius: $radius-lg;
 60→  box-shadow: $shadow-popover;
 61→  z-index: $z-search-dropdown;
 62→  animation: search-dropdown-appear $transition-normal ease-out both;
 63→}
 64→
 65→.search-dropdown__menu-content {
 66→  padding: $space-1;
 67→  overflow-y: auto;
 68→  max-height: calc($search-dropdown-menu-max-height - 2 * $space-1);
 69→}
 70→
 71→.search-dropdown__separator {
 72→  height: 1px;
 73→  margin: $space-1 $space-2;
 74→  background-color: $border-100;
 75→}
 76→
 77→.search-dropdown__section-title {
 78→  padding: $space-1 + $space-half $space-3;
 79→  font-family: $font-family;
 80→  font-size: $font-xs;
 81→  font-weight: $font-weight-medium;
 82→  color: $text-400;
 83→  line-height: 1;
 84→  white-space: nowrap;
 85→  user-select: none;
 86→}
 87→
 88→.search-dropdown__option {
 89→  display: flex;
 90→  align-items: center;
 91→  gap: $space-2;
 92→  width: 100%;
 93→  padding: $space-2 $space-3;
 94→  background: none;
 95→  border-radius: $radius-md;
 96→  cursor: pointer;
 97→  color: $color-text-primary;
 98→  font-family: $font-family;
 99→  font-size: $font-sm;
100→  line-height: 1;
101→  text-align: left;
102→  transition: background-color $transition-fast ease;
103→
104→  &:hover,
105→  &--active {
106→    background-color: $color-accent;
107→    color: $color-text-on-accent;
108→
109→    .search-dropdown__check {
110→      color: $color-text-on-accent;
111→    }
112→  }
113→
114→  &:focus-visible {
115→    outline: 2px solid $color-accent;
116→    outline-offset: -2px;
117→    border-radius: $radius-md;
118→  }
119→}
120→
121→.search-dropdown__option-icon {
122→  display: flex;
123→  align-items: center;
124→  justify-content: center;
125→  flex-shrink: 0;
126→  width: 16px;
127→  height: 16px;
128→}
129→
130→.search-dropdown__option-label {
131→  flex: 1;
132→  white-space: nowrap;
133→}
134→
135→.search-dropdown__check {
136→  flex-shrink: 0;
137→  color: $color-accent;
138→}
139→
140→@keyframes search-dropdown-appear {
141→  from {
142→    opacity: 0;
143→    transform: scale(0.96) translateY(-4px);
144→  }
145→
146→  to {
147→    opacity: 1;
148→    transform: scale(1) translateY(0);
149→  }
150→}
