  1→import {
  2→  type KeyboardEvent,
  3→  type ReactNode,
  4→  Fragment,
  5→  useEffect,
  6→  useRef,
  7→} from 'react';
  8→import type { BreadcrumbItem } from '../../hooks/use_navigation';
  9→import './search_bar.scss';
 10→
 11→interface SearchBarProps {
 12→  value: string;
 13→  onChange: (value: string) => void;
 14→  placeholder?: string;
 15→  activeDescendantId?: string;
 16→  breadcrumbs?: BreadcrumbItem[];
 17→  dropdown?: ReactNode;
 18→}
 19→
 20→export function SearchBar({
 21→  value,
 22→  onChange,
 23→  placeholder = 'Search...',
 24→  activeDescendantId,
 25→  breadcrumbs,
 26→  dropdown,
 27→}: SearchBarProps) {
 28→  const inputRef = useRef<HTMLInputElement>(null);
 29→
 30→  useEffect(() => {
 31→    inputRef.current?.focus();
 32→  }, []);
 33→
 34→  function handleInputKeyDown(e: KeyboardEvent<HTMLInputElement>) {
 35→    if (e.key !== 'Escape' || !breadcrumbs || breadcrumbs.length === 0) {
 36→      return;
 37→    }
 38→
 39→    e.preventDefault();
 40→    if (value) {
 41→      onChange('');
 42→      return;
 43→    }
 44→
 45→    for (let i = breadcrumbs.length - 1; i >= 0; i--) {
 46→      const crumb = breadcrumbs[i];
 47→      if (crumb?.onBack) {
 48→        crumb.onBack();
 49→        return;
 50→      }
 51→    }
 52→  }
 53→
 54→  return (
 55→    <div className="search-bar" role="search">
 56→      <svg
 57→        className="search-bar__icon"
 58→        width="20"
 59→        height="20"
 60→        viewBox="0 0 20 20"
 61→        fill="none"
 62→        xmlns="http://www.w3.org/2000/svg"
 63→      >
 64→        <circle cx="9" cy="9" r="5.5" stroke="currentColor" strokeWidth="1.5" />
 65→        <line
 66→          x1="13.25"
 67→          y1="13.25"
 68→          x2="17.5"
 69→          y2="17.5"
 70→          stroke="currentColor"
 71→          strokeWidth="1.5"
 72→          strokeLinecap="round"
 73→        />
 74→      </svg>
 75→      {breadcrumbs && breadcrumbs.length > 0 && (
 76→        <nav className="search-bar__breadcrumbs" aria-label="Breadcrumb">
 77→          {breadcrumbs.map((crumb, i) => {
 78→            const isLast = i === breadcrumbs.length - 1;
 79→            return (
 80→              <Fragment key={i}>
 81→                {i > 0 && (
 82→                  <svg
 83→                    className="search-bar__breadcrumb-chevron"
 84→                    width="8"
 85→                    height="8"
 86→                    viewBox="0 0 8 8"
 87→                    fill="none"
 88→                    aria-hidden="true"
 89→                  >
 90→                    <path
 91→                      d="M2.5 1.5L5.5 4L2.5 6.5"
 92→                      stroke="currentColor"
 93→                      strokeWidth="1.2"
 94→                      strokeLinecap="round"
 95→                      strokeLinejoin="round"
 96→                    />
 97→                  </svg>
 98→                )}
 99→                {isLast ? (
100→                  <span
101→                    className="search-bar__breadcrumb search-bar__breadcrumb--current"
102→                    aria-current="location"
103→                  >
104→                    {crumb.label}
105→                  </span>
106→                ) : (
107→                  <button
108→                    className="search-bar__breadcrumb"
109→                    onClick={crumb.onBack}
110→                    type="button"
111→                    aria-label={`Back to ${crumb.label}`}
112→                  >
113→                    {crumb.label}
114→                  </button>
115→                )}
116→              </Fragment>
117→            );
118→          })}
119→        </nav>
120→      )}
121→      <input
122→        ref={inputRef}
123→        className="search-bar__input"
124→        type="text"
125→        value={value}
126→        onChange={e => onChange(e.target.value)}
127→        onKeyDown={handleInputKeyDown}
128→        placeholder={placeholder}
129→        role="combobox"
130→        aria-expanded={true}
131→        aria-controls="command-list"
132→        aria-activedescendant={activeDescendantId}
133→        aria-label="Search commands"
134→        spellCheck={false}
135→        autoComplete="off"
136→      />
137→      {dropdown}
138→    </div>
139→  );
140→}
