  &--open { transform: rotate(180deg); }
}

.search-dropdown__menu {
  position: absolute;
  top: calc(100% + $space-2);  // 8px below trigger
  right: 0;
  min-width: $search-dropdown-menu-min-width; // 180px
  max-height: $search-dropdown-menu-max-height; // 240px
  background-color: $color-surface;  // #232325
  border: 1px solid $border-100;
  border-radius: $radius-lg;  // 12px
  box-shadow: $shadow-popover;
  z-index: $z-search-dropdown; // 110
  animation: search-dropdown-appear 150ms ease-out both;
}

.search-dropdown__option {
  display: flex;
  align-items: center;
  gap: $space-2;  // 8px
  width: 100%;
  padding: $space-2 $space-3; // 8px 12px
  border-radius: $radius-md;  // 8px
  cursor: pointer;
  color: $color-text-primary;
  font-size: $font-sm;
  line-height: 1;
  transition: background-color 80ms ease;

  &:hover,
  &--active {
    background-color: $color-accent;      // #007aff
    color: $color-text-on-accent;         // #ffffff
    .search-dropdown__check { color: $color-text-on-accent; }
  }
}

@keyframes search-dropdown-appear {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(-4px);
  }
  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}
```

