### 12. COLOR PICKER VIEW IN APP.tsx (`src/App.tsx` lines 177-216)

```typescript
interface ColorPickerViewProps {
  colors: ColorItemData[];
  onActiveIndexChange: (index: number) => void;
  onAction: (index: number) => void;
}

function ColorPickerView({
  colors,
  onActiveIndexChange,
  onAction,
}: ColorPickerViewProps) {
  if (colors.length === 0) {
    return <EmptyState icon={<SearchIcon />} title="No Colors" />;
  }

  return (
    <Grid
      itemCount={colors.length}
      columns={4}
      onActiveIndexChange={onActiveIndexChange}
      onAction={onAction}
    >
      {colors.map((color, index) => (
        <GridItem
          key={color.id}
          index={index}
          icon={<ColorSwatch color={color.color} />}
          title={color.title}
          subtitle={color.subtitle}
        />
      ))}
    </Grid>
  );
}

function ColorSwatch({ color }: { color: string }) {
  return (
    <div
      className="grid-item__color-swatch"
      style={{ backgroundColor: color }}
    />
  );
}
```

**Integration in App**:
- ColorPickerView is used when navigating to 'Color Picker' command
- `handleGridAction` callback copies color to clipboard and shows HUD confirmation
- Filter by query text (title or subtitle)

